(15, '❤️ Reliable Walking Services .', '', '<p>Busy schedule ? No problem! Our professional dog walking services ensure your pets get the daily exercise, fresh air, and attention they need. Rain or shine, we are there for your furry friend.</p>', 'category/3.png', '2021-12-20'),
(16, '❤️Safety First, Always .', '', 'Your pet s safety is our #1 priority. We use secure leashes, follow all safety protocols, and only walk one household at a time (unless otherwise requested) for personalized attention.', 'category/1.JPG', '2025-03-10');
