(2, 'Asish Samanta', 'sunriseacademy.sradmy@gmail.com', '9609535629', 'English I Arts I Life Science', 'B.A (H) English C.U\r\nSpecial Interest in Political Science, Life Science, Bengali\r\nDirector of Sunrise Academy since 2005\r\n\r\nআমি একজন শিক্ষক ও মেন্টর হিসেবে আমার ছাত্রছাত্রীদের শুধু পাঠ্যবিষয় শেখানোর দায়িত্বই নিই না, আমি তাদের ভবিষ্যৎ গঠনের দায়িত্বও অনুভব করি। আমি প্রতিটি ছাত্রের মানসিক, শারীরিক ও শিক্ষাগত প্রয়োজনের দিকে সমানভাবে নজর দিই। যাদের দুর্বলতা আছে, আমি তাদের আলাদাভাবে সময় দিয়ে সাহায্য করি। আমি বিশ্বাস করি, স্নেহ,সহানুভূতি ও ধৈর্যই একজন শিক্ষকের প্রধান গুণ। তাই আমি সবসময় চেষ্টা করি আমার ছাত্রদের আত্মবিশ্বাস জাগাতে, তাদের পাশে থাকতে, এবং একজন ভালো মানুষ হিসেবে গড়ে তুলতে।তাদের সাফল্যই আমার সবচেয়ে বড় প্রাপ্তি।', 'images/1752255209_1752255009311.jpg', '2025-05-22 16:54:04'),
(4, 'Soumoditya Majhi', 'sunriseacademy.sradmy@gmail.com', '9609535629', 'Drawing Instructor | Practicing Artist', 'I\'m Soumoditya Majhi—a drawing instructor and practicing artist with a deep passion for visual art. I completed my formal training at Surovaroti Sangeet Parishad, and ever since, art has been both my profession and my personal journey.\r\n\r\nTeaching has given me the chance to share what I love most—helping students of all ages discover their creativity and build confidence in their skills. I believe in teaching with patience, understanding, and lots of hands-on practice, always tailoring my approach to each individual’s pace and potential.', 'images/sss.jpeg', '2025-07-17 12:51:36'),
(5, 'Akash Rang', 'sunriseacademy.sradmy@gmail.com', '9609535629', 'Political Science I General Arts Guide', 'B.A Hons In Political Science in 2025 from Calcutta University. B. Ed Running from Seacom College.', 'images/WhatsApp Image 2025-07-17 at 12.53.45 PM.jpeg', '2025-07-17 13:00:03');
INSERT INTO `testimonial` (`id`, `student_name`, `image`, `comment`, `date`) VALUES
(6, 'Annesha Lahiri', 'testimonial/0.png', 'Archita s Dog Creche is a haven for our furry friends! The staff is incredibly caring, and my dog always comes home happy and well-rested. Highly recommended for pet parents who want their dogs treated like family.', '21/12/2020'),
(7, 'Poushali Dutta', 'testimonial/0.png', 'Amazing service at Archita s Dog Creche! They go above and beyond to ensure my dog is safe, happy, and entertained. I love seeing the fun updates and photos throughout the day!', '20-02-2020'),
(8, 'Sinchan Sengupta', 'testimonial/avater3.png', 'What a wonderful experience at Archita s Dog Creche! The staff treats each dog like their own, and the playtime activities keep my dog engaged and happy. Thank you for taking such great care of her!', '23/12/2021'),
(9, 'Aishwarya Bhattacharyya', 'testimonial/0.png', 'Highly recommend Archita s Dog Creche for anyone who needs a safe and loving space for their dog. The attention to detail and the care provided is second to none!', '02/02/2021');
